	data <- formr::formr_raw_results(survey_name = "Fragebogen_fragen",
	                         host = "https://formr.uni-muenster.de")

	data[["working_time_week"]][data[["working_time_week"]] == 0] <- NA

	data2 <- subset(data, select = -c(expired,ended,specificity_2_pg,
	                                  specificity_3_pg,specificity_2_lg,
	                                  specificity_3_lg,working_time_week))[complete.cases(subset(data, select = -c(expired,ended,specificity_2_pg,
