	                                                                                                               specificity_3_lg))),]

	if (as.numeric(table(data2$goal_content)["no goal"]) == as.numeric(table(data2$goal_content)["performance goal"]) &&
	    as.numeric(table(data2$goal_content)["performance goal"]) == as.numeric(table(data2$goal_content)["learning goal"])) {
	  sample(1:3, 1)
	} else if (as.numeric(table(data2$goal_content)["no goal"]) <= as.numeric(table(data2$goal_content)["performance goal"]) &&
